import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
ws = wb['Sheet1']
print(f'Max row: {ws.max_row}, Max col: {ws.max_column}')
for row in ws.iter_rows(min_row=1, max_row=ws.max_row, max_col=ws.max_column, values_only=False):
    for cell in row:
        if cell.value is not None:
            border = cell.border
            parts = []
            if border.top.style: parts.append('top=' + border.top.style)
            if border.bottom.style: parts.append('bottom=' + border.bottom.style)
            if border.left.style: parts.append('left=' + border.left.style)
            if border.right.style: parts.append('right=' + border.right.style)
            border_info = ' [BORDER: ' + ', '.join(parts) + ']' if parts else ''
            print(f'  {cell.coordinate}: {repr(cell.value)}{border_info}')
